1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	
12	type Damage = { itemType: string; amount: number };
13	
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: Damage[] };
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	type ScenarioResult = {
28	  results: { premium?: number; payout?: number }[];
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	
35	const firstInsuranceSurcharge = (premium: number): number =>
36	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
37	
38	const COMPONENT_PREMIUM = 25;
39	
40	const BASE_PREMIUMS: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: COMPONENT_PREMIUM,
46	  moonstone: COMPONENT_PREMIUM,
47	};
48	
49	const BLOCK_PREMIUM = 60;
50	
51	const isBlock = (count: number): boolean => count === 3;
52	
53	const countByType = (items: Item[]): Record<string, number> =>
54	  items.reduce<Record<string, number>>((counts, item) => {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	
59	const premiumForGroup = (type: string, count: number): number =>
60	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
61	
62	const basePremiumFor = (items: Item[]): number =>
63	  Object.entries(countByType(items)).reduce(
64	    (total, [type, count]) => total + premiumForGroup(type, count),
65	    0,
66	  );
67	
68	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
69	
70	const surchargeFor = (
71	  items: Item[],
72	  qualifies: (item: Item) => boolean,
73	  rate: number,
74	): number =>
75	  items.reduce(
76	    (total, item) =>
77	      total + (qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0),
78	    0,
79	  );
80	
81	const CURSE_SURCHARGE_RATE = 0.5;
82	
83	const isCursed = (item: Item): boolean => item.cursed === true;
84	
85	const curseSurchargeFor = (items: Item[]): number =>
86	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
87	
88	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
89	
90	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
91	
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
94	
95	const enchantmentSurchargeFor = (items: Item[]): number =>
96	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
97	
98	const discountFor = (
99	  qualifies: boolean,
100	  premium: number,
101	  rate: number,
102	): number => (qualifies ? premium * rate : 0);
103	
104	const LOYALTY_DISCOUNT_RATE = 0.2;
105	
106	const LOYALTY_YEARS_THRESHOLD = 2;
107	
108	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
109	  discountFor(
110	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
111	    premium,
112	    LOYALTY_DISCOUNT_RATE,
113	  );
114	
115	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
116	
117	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
118	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
119	
120	const quotePremium = (
121	  customer: Customer,
122	  items: Item[],
123	  isFollowUp: boolean,
124	): number => {
125	  const basePremium = basePremiumFor(items);
126	  return roundUpToWholeGold(
127	    basePremium +
128	      curseSurchargeFor(items) +
129	      enchantmentSurchargeFor(items) +
130	      firstInsuranceSurcharge(basePremium) -
131	      loyaltyDiscountFor(customer, basePremium) -
132	      followUpDiscountFor(isFollowUp, basePremium) +
133	      PROCESSING_FEE,
134	  );
135	};
136	
137	const DEDUCTIBLE = 100;
138	
139	const HIGH_ENCHANTMENT_THRESHOLD = 8;
140	
141	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
142	
143	const reimbursementRateFor = (item: Item | undefined): number =>
144	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
145	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
146	    : 1;
147	
148	const payoutForDamage = (insuredItems: Item[], damage: Damage): number => {
149	  const insuredItem = insuredItems.find(
150	    (item) => item.type === damage.itemType,
151	  );
152	  return damage.amount * reimbursementRateFor(insuredItem) - DEDUCTIBLE;
153	};
154	
155	const insuredItemsForPolicy = (steps: Step[], policy: number): Item[] => {
156	  const policyStep = steps[policy];
157	  return policyStep.op === "quote" ? policyStep.items : [];
158	};
159	
160	const claimPayout = (steps: Step[], step: ClaimStep): number => {
161	  const insuredItems = insuredItemsForPolicy(steps, step.policy);
162	  return step.incident.damages.reduce(
163	    (total, damage) => total + payoutForDamage(insuredItems, damage),
164	    0,
165	  );
166	};
167	
168	export const runScenario = (scenario: Scenario): ScenarioResult => ({
169	  results: scenario.steps.map((step, index) =>
170	    step.op === "quote"
171	      ? { premium: quotePremium(scenario.customer, step.items, index > 0) }
172	      : { payout: claimPayout(scenario.steps, step) },
173	  ),
174	});
